# ─────────────────────────────────────────────────────────────────────────
# Master dispatcher: validate_transition
#   rdi (edi) = current_state, rsi (esi) = next_state, rdx = prerequisites
#   Returns: 1 = valid, 0 = invalid
# ─────────────────────────────────────────────────────────────────────────
.globl validate_transition
.type  validate_transition, @function
validate_transition:
    # Bounds check: 0 <= current_state <= 7
    cmp  edi, 0
    jl   .Linvalid_transition_main
    cmp  edi, 7
    jg   .Linvalid_transition_main

    # Bounds check: 0 <= next_state <= 7
    cmp  esi, 0
    jl   .Linvalid_transition_main
    cmp  esi, 7
    jg   .Linvalid_transition_main

    # Reset: next_state == 0 is always valid
    test esi, esi
    jz   .Lvalid_transition_main

    # Sequential check: next_state must equal current_state + 1
    mov  eax, edi
    inc  eax
    cmp  esi, eax
    jne  .Linvalid_transition_main

    # Prerequisite bit check: bit (next_state - 1) must be set in rdx
    mov  ecx, esi
    dec  ecx                # ecx = next_state - 1
    mov  rax, 1
    shl  rax, cl            # rax = 1 << (next_state - 1)
    test rdx, rax           # check if bit is set in prerequisites (rdx)
    jz   .Linvalid_transition_main

.Lvalid_transition_main:
    mov  eax, 1
    ret

.Linvalid_transition_main:
    xor  eax, eax
    ret

.size validate_transition, .-validate_transition

